def batches(rows, size):
    batch = []
    try:
        for row in rows:
            batch.append(row)
            if len(batch) == size:
                yield tuple(batch); batch.clear()
        if batch: yield tuple(batch)
    finally: print("pipeline closed")
stream = batches(range(7), 3)
print(next(stream))
stream.close()

