from threading import Lock
class Counter:
    def __init__(self): self._value, self._lock = 0, Lock()
    def increment(self):
        with self._lock:
            current = self._value
            self._value = current + 1
    @property
    def value(self):
        with self._lock: return self._value
counter = Counter(); counter.increment(); print(counter.value)

